function buildBolt(start, end, segments, jitter) {
  const pts = [start.clone()];
  const dir = end.clone().sub(start);
  const len = dir.length();
  const step = dir.clone().multiplyScalar(1 / segments);
  const perp = new THREE.Vector3(-step.y, step.x, 0).normalize();
  for (let i = 1; i < segments; i++) {
    const p = start.clone().add(step.clone().multiplyScalar(i));
    p.add(perp.clone().multiplyScalar((Math.random() - 0.5) * jitter * len));
    pts.push(p);
  }
  pts.push(end.clone());
  return new THREE.BufferGeometry().setFromPoints(pts);
}
